definition.script:
def parseLabels(String raw) {
  return raw.split(',').collect { it.trim() }.findAll { it }
}

def parseAvailable(String raw) {
  return raw.split(',').collect { it.trim() }.findAll { it }.collect { entry ->
    def parts = entry.split('=', 2)
    def label = parts[0].trim()
    def image = parts.length > 1 ? parts[1].trim() : label
    return [label: label, image: image]
  }
}

def safeName(String value) {
  return value.replaceAll('[^A-Za-z0-9_.-]', '_')
}

pipeline {
  agent none
  options {
    timeout(time: 8, unit: 'HOURS')
    buildDiscarder(logRotator(numToKeepStr: '20'))
  }
  stages {
    stage('Matrix inventory') {
      steps {
        node('built-in') {
          script {
            def requested = parseLabels(params.REQUESTED_KERNELS)
            def available = parseAvailable(params.AVAILABLE_KERNELS)
            def availableLabels = available.collect { it.label }
            def missing = requested.findAll { !availableLabels.contains(it) }
            def scenarioCount = params.SCENARIO_COUNT as Integer
            if (scenarioCount < 500 || scenarioCount > 1000) {
              error("SCENARIO_COUNT must be between 500 and 1000 for the advanced matrix")
            }
            if (requested.isEmpty()) {
              error('REQUESTED_KERNELS did not contain any labels')
            }
            if (available.isEmpty()) {
              error('AVAILABLE_KERNELS did not contain any real Firecracker image entries')
            }
            sh 'rm -rf matrix && mkdir -p matrix'
            writeFile file: 'matrix/requested-kernels.txt', text: requested.join('\n') + '\n'
            writeFile file: 'matrix/available-kernels.txt',
              text: available.collect { "${it.label}=${it.image}" }.join('\n') + '\n'
            writeFile file: 'matrix/missing-kernels.txt', text: missing.join('\n') + (missing ? '\n' : '')
            writeFile file: 'matrix/covered-kernels.txt', text: ''
            writeFile file: 'matrix/summary.txt',
              text: "requested=${requested.size()}\navailable=${available.size()}\nmissing=${missing.size()}\nscenario_count=${scenarioCount}\nrequire_all=${params.REQUIRE_ALL_KERNELS}\n"
            archiveArtifacts artifacts: 'matrix/*.txt', fingerprint: true
          }
        }
      }
    }
    stage('Firecracker advanced e2e') {
      steps {
        script {
          def requested = parseLabels(params.REQUESTED_KERNELS)
          def available = parseAvailable(params.AVAILABLE_KERNELS)
          def availableLabels = available.collect { it.label }
          def missing = requested.findAll { !availableLabels.contains(it) }
          def branches = [:]
          for (def entry in available) {
            def kernelId = entry.label
            def imageName = entry.image
            def safeKernel = safeName(kernelId)
            branches[kernelId] = {
              firecrackerAgent(cloud: 'firecracker', image: imageName, cpus: 2, memory: '2g', evidence: true) {
                withEnv([
                  "OPAMROOT=${env.WORKSPACE}/.opam",
                  'DEBIAN_FRONTEND=noninteractive',
                  "LPF_KERNEL_ID=${kernelId}",
                  "LPF_SAFE_KERNEL=${safeKernel}",
                  "LPF_FIRECRACKER_IMAGE=${imageName}"
                ]) {
                  stage("VM identity ${kernelId}") {
                    sh '''
                      set -eu
                      uname -a | tee "kernel-${LPF_SAFE_KERNEL}.txt"
                      cat /etc/os-release || true
                      id
                      hostname || true
                    '''
                  }
                  stage("Install toolchain ${kernelId}") {
                    sh '''
                      set -eux
                      if command -v sudo >/dev/null 2>&1; then SUDO=sudo; else SUDO=; fi
                      if command -v apt-get >/dev/null 2>&1; then
                        $SUDO apt-get update -qq
                        $SUDO apt-get install -y --no-install-recommends \
                          ca-certificates curl git build-essential ocaml opam m4 pkg-config bubblewrap \
                          nftables iproute2 iputils-ping conntrack kmod procps tar gzip xz-utils
                      elif command -v dnf >/dev/null 2>&1; then
                        $SUDO dnf install -y \
                          ca-certificates curl git gcc gcc-c++ make ocaml opam m4 pkgconf-pkg-config bubblewrap \
                          nftables iproute iputils conntrack-tools kmod procps-ng tar gzip xz
                      elif command -v apk >/dev/null 2>&1; then
                        $SUDO apk add --no-cache \
                          ca-certificates curl git build-base ocaml opam m4 pkgconf bubblewrap \
                          nftables iproute2 iputils conntrack-tools kmod procps tar gzip xz
                      else
                        echo "unsupported guest package manager" >&2
                        exit 1
                      fi
                      ocamlc -version
                      opam --version
                      if [ ! -d "$OPAMROOT" ]; then opam init --bare --disable-sandboxing -y; fi
                      if ! opam switch list --short | grep -qx lpf-ci; then
                        opam switch create lpf-ci ocaml-system -y
                      fi
                      eval "$(opam env --switch=lpf-ci)"
                      opam install dune -y
                      dune --version
                      nft --version
                      ip -Version
                      tc -Version
                      conntrack -V
                    '''
                  }
                  stage("Checkout ${kernelId}") {
                    sh '''
                      set -eux
                      rm -rf lpf lpf.tar.gz lpf.commit evidence allure-results matrix
                      host_gateway="$(ip route show default | awk 'NR==1 {print $3}')"
                      base_url="${SOURCE_ARCHIVE_BASE_URL:-http://${host_gateway}:18081}"
                      curl -fsSL "${base_url}/lpf-${EXPECTED_COMMIT}.tar.gz" -o lpf.tar.gz
                      mkdir lpf
                      tar -xzf lpf.tar.gz -C lpf
                      curl -fsSL "${base_url}/lpf-${EXPECTED_COMMIT}.commit" -o lpf/.source-commit
                      grep -q "^${EXPECTED_COMMIT}" lpf/.source-commit
                    '''
                  }
                  stage("Build and unit tests ${kernelId}") {
                    sh '''
                      set -eux
                      eval "$(opam env --switch=lpf-ci)"
                      cd lpf
                      dune build
                      dune runtest
                      ./_build/default/bin/main.exe man check --dir man/generated
                    '''
                  }
                  stage("E2E scenarios ${kernelId}") {
                    sh '''
                      set -eux
                      eval "$(opam env --switch=lpf-ci)"
                      mkdir -p "evidence/${LPF_SAFE_KERNEL}" "allure-results/${LPF_SAFE_KERNEL}" "matrix"
                      cd lpf
                      {
                        printf 'git_commit='
                        cat .source-commit
                        printf 'kernel_id=%s\n' "$LPF_KERNEL_ID"
                        printf 'firecracker_image=%s\n' "$LPF_FIRECRACKER_IMAGE"
                        printf 'kernel_release='
                        uname -r
                        printf 'os_release='
                        ( . /etc/os-release && printf '%s %s\n' "${ID:-unknown}" "${VERSION_ID:-unknown}" ) || true
                        printf 'ocaml_version='
                        ocamlc -version
                        printf 'dune_version='
                        dune --version
                        printf 'nft_version='
                        nft --version
                        printf 'iproute2_version='
                        ip -Version
                        printf 'tc_version='
                        tc -Version
                        printf 'conntrack_version='
                        conntrack -V
                        printf 'command_under_test=lpf e2e run --scenario-count %s\n' "$SCENARIO_COUNT"
                        printf 'policy_fixture_path=e2e/generated-catalog\n'
                      } > "../evidence/${LPF_SAFE_KERNEL}/environment.txt"
                      set +e
                      ./_build/default/bin/main.exe e2e run \
                        --scenario-count "$SCENARIO_COUNT" \
                        --junit "../evidence/${LPF_SAFE_KERNEL}/junit.xml" \
                        --allure-dir "../allure-results/${LPF_SAFE_KERNEL}" \
                        --evidence-dir "../evidence/${LPF_SAFE_KERNEL}" \
                        --kernel-id "$LPF_KERNEL_ID"
                      e2e_status="$?"
                      set -e
                      printf '%s\n' "$e2e_status" > "../evidence/${LPF_SAFE_KERNEL}/e2e.exit"
                      if [ "$e2e_status" = 0 ]; then
                        printf '%s\n' "$LPF_KERNEL_ID" > "../evidence/${LPF_SAFE_KERNEL}/covered-kernel.txt"
                        printf '%s\n' "$LPF_KERNEL_ID" > "../matrix/covered-${LPF_SAFE_KERNEL}.txt"
                      fi
                      if [ -f "../evidence/${LPF_SAFE_KERNEL}/scenario-log.jsonl" ]; then
                        (cd "../evidence/${LPF_SAFE_KERNEL}" && sha256sum manifest.json scenario-log.jsonl junit.xml > checksums.sha256)
                      fi
                      exit 0
                    '''
                  }
                  stage("Publish ${kernelId}") {
                    junit allowEmptyResults: true, testResults: "evidence/${safeKernel}/junit.xml"
                    catchError(buildResult: 'UNSTABLE', stageResult: 'UNSTABLE') {
                      step([
                        $class: 'org.allurereport.jenkins.AllureReportPublisher',
                        includeProperties: false,
                        reportBuildPolicy: 'ALWAYS',
                        results: [[path: "allure-results/${safeKernel}"]]
                      ])
                    }
                    archiveArtifacts artifacts: "kernel-${safeKernel}.txt,evidence/${safeKernel}/**,allure-results/${safeKernel}/**,matrix/covered-${safeKernel}.txt", allowEmptyArchive: true, fingerprint: true
                    sh "test \"\$(cat evidence/${safeKernel}/e2e.exit)\" = 0"
                  }
                }
              }
            }
          }
          parallel branches
          if (params.REQUIRE_ALL_KERNELS && !missing.isEmpty()) {
            error("Missing requested Firecracker kernels: ${missing.join(', ')}")
          }
        }
      }
    }
  }
}
